 1→//! Shared domain types for the Forge runtime platform.
 2→//!
 3→//! This crate defines the core domain types shared across `forge-cli`,
 4→//! `forge-runtime`, and `forge-proto`: identifiers, agent manifests,
 5→//! run-plan / task-graph structures, policy definitions, and runtime events.
 6→//!
 7→//! All types are designed for strong typing (newtype IDs, enums with data),
 8→//! serde support (for persistence and gRPC translation), and clear ownership
 9→//! semantics aligned with the runtime platform design spec.
10→
11→pub mod events;
12→pub mod ids;
13→pub mod manifest;
14→pub mod policy;
15→pub mod run_graph;
16→pub mod runtime;
17→
18→// Re-export commonly used types at the crate root for convenience.
19→pub use events::{BusMessage, RuntimeEvent, RuntimeEventKind, TaskOutput, TaskOutputEvent};
20→pub use ids::{AgentId, ApprovalId, ChannelId, MilestoneId, RunId, SpawnId, TaskNodeId};
21→pub use manifest::{
22→    AgentManifest, BudgetEnvelope, CapabilityEnvelope, CompiledProfile, CredentialAccessMode,
23→    CredentialGrant, MemoryPolicy, MemoryScope, PermissionSet, RepoAccess, ResourceLimits,
24→    RunSharedWriteMode, RuntimeEnvPlan, SpawnLimits, WorktreePlan,
25→};
26→pub use policy::{Policy, PolicyDecision};
27→pub use run_graph::{
28→    AgentHandle, AgentInstance, AgentResult, ApprovalActorKind, ApprovalMode,
29→    ApprovalReasonKind, ApprovalResolution, ApprovalState, MilestoneInfo, MilestoneState,
30→    MilestoneStatus, PendingApproval, ResourceSnapshot, RunGraph, RunPlan, RunState, RunStatus,
31→    TaskNode, TaskResultSummary, TaskStatus, TaskTemplate, TaskWaitMode,
32→};
33→

   1→// Copyright 2026 Forge Contributors
   2→// SPDX-License-Identifier: Apache-2.0
   3→//
   4→// Forge Runtime Platform — gRPC contract between forge CLI / Factory clients
   5→// and the forge-runtime daemon. Communicates over a Unix domain socket at
   6→// $FORGE_RUNTIME_DIR/forge.sock.
   7→//
   8→// Design reference: docs/superpowers/specs/2026-03-13-forge-runtime-platform-design.md
   9→
  10→syntax = "proto3";
  11→
  12→package forge.runtime.v1;
  13→
  14→import "google/protobuf/timestamp.proto";
  15→import "google/protobuf/duration.proto";
  16→import "google/protobuf/struct.proto";
  17→
  18→option java_multiple_files = true;
  19→option java_package = "com.forge.runtime.v1";
  20→option go_package = "forge/runtime/v1;runtimev1";
  21→
  22→// ---------------------------------------------------------------------------
  23→// Service
  24→// ---------------------------------------------------------------------------
  25→
  26→// ForgeRuntime is the primary API exposed by the forge-runtime daemon.
  27→// CLI, Factory, and agent processes connect over a Unix domain socket.
  28→service ForgeRuntime {
  29→  // ---- Run lifecycle -------------------------------------------------------
  30→
  31→  // Submit a new run for execution. The daemon validates policy, persists the
  32→  // run, and begins scheduling. Returns the initial RunInfo snapshot.
  33→  rpc SubmitRun(SubmitRunRequest) returns (RunInfo);
  34→
  35→  // Attach to a running (or completed) run and receive a replay of events
  36→  // after `after_cursor`, followed by a live tail. Supports
  37→  // CLI disconnect/reconnect without state loss.
  38→  rpc AttachRun(AttachRunRequest) returns (stream RuntimeEvent);
  39→
  40→  // Request graceful stop of a run. In-flight tasks receive SIGTERM; the
  41→  // daemon waits a grace period before force-killing.
  42→  rpc StopRun(StopRunRequest) returns (RunInfo);
  43→
  44→  // Fetch the current snapshot of a run.
  45→  rpc GetRun(GetRunRequest) returns (RunInfo);
  46→
  47→  // List runs, optionally filtered by project or status.
  48→  rpc ListRuns(ListRunsRequest) returns (ListRunsResponse);
  49→
  50→  // ---- Task lifecycle ------------------------------------------------------
  51→
  52→  // Fetch a single task node.
  53→  rpc GetTask(GetTaskRequest) returns (TaskInfo);
  54→
  55→  // List task nodes within a run.
  56→  rpc ListTasks(ListTasksRequest) returns (ListTasksResponse);
  57→
  58→  // Stream a task-scoped filtered projection of output chunks from the
  59→  // authoritative runtime event log.
  60→  rpc StreamTaskOutput(StreamTaskOutputRequest) returns (stream TaskOutputEvent);
  61→
  62→  // Create a child task node under an existing parent. The daemon runs the
  63→  // request through the policy engine and may gate on approval.
  64→  rpc CreateChildTask(CreateChildTaskRequest) returns (CreateChildTaskResponse);
  65→
  66→  // Terminate a task. The daemon sends SIGTERM to the agent, waits a grace
  67→  // period, then SIGKILL.
  68→  rpc KillTask(KillTaskRequest) returns (KillTaskResponse);
  69→
  70→  // ---- Approval flow -------------------------------------------------------
  71→
  72→  // Stream pending approval requests. The daemon pushes new requests as they
  73→  // arise; the client resolves them via ResolveApproval.
  74→  rpc PendingApprovals(PendingApprovalsRequest) returns (stream ApprovalRequest);
  75→
  76→  // Approve or deny a pending approval request.
  77→  rpc ResolveApproval(ResolveApprovalRequest) returns (ResolveApprovalResponse);
  78→
  79→  // ---- MCP service management ----------------------------------------------
  80→
  81→  // Register a new MCP server with the daemon's MCP router at runtime.
  82→  rpc RegisterMcpServer(RegisterMcpServerRequest) returns (McpServerInfo);
  83→
  84→  // List currently registered MCP servers.
  85→  rpc ListMcpServers(ListMcpServersRequest) returns (ListMcpServersResponse);
  86→
  87→  // ---- Observability -------------------------------------------------------
  88→
  89→  // Stream daemon-wide runtime events (all runs). Supports replay from a
  90→  // sequence number for durable consumption.
  91→  rpc StreamEvents(StreamEventsRequest) returns (stream RuntimeEvent);
  92→
  93→  // Fetch a point-in-time metrics snapshot (Prometheus-compatible counters
  94→  // and gauges).
  95→  rpc GetMetrics(GetMetricsRequest) returns (MetricsSnapshot);
  96→
  97→  // ---- Daemon management ---------------------------------------------------
  98→
  99→  // Health check with version negotiation. Clients MUST call this on connect
 100→  // and verify protocol_version compatibility before issuing other RPCs.
 101→  rpc Health(HealthRequest) returns (HealthResponse);
 102→
 103→  // Initiate graceful daemon shutdown. Running agents receive Shutdown
 104→  // messages via the bus and are given a grace period.
 105→  rpc Shutdown(ShutdownRequest) returns (ShutdownResponse);
 106→}
 107→
 108→// ---------------------------------------------------------------------------
 109→// Enums
 110→// ---------------------------------------------------------------------------
 111→
 112→// Status of a run within the daemon.
 113→enum RunStatus {
 114→  RUN_STATUS_UNSPECIFIED = 0;
 115→  RUN_STATUS_SUBMITTED   = 1;
 116→  RUN_STATUS_SCHEDULING  = 2;
 117→  RUN_STATUS_RUNNING     = 3;
 118→  RUN_STATUS_PAUSED      = 4;
 119→  RUN_STATUS_COMPLETED   = 5;
 120→  RUN_STATUS_FAILED      = 6;
 121→  RUN_STATUS_CANCELLED   = 7;
 122→}
 123→
 124→// Status of a task node within the run graph.
 125→enum TaskStatus {
 126→  TASK_STATUS_UNSPECIFIED       = 0;
 127→  TASK_STATUS_PENDING           = 1;
 128→  TASK_STATUS_AWAITING_APPROVAL = 2;
 129→  TASK_STATUS_ENQUEUED          = 3;
 130→  TASK_STATUS_MATERIALIZING     = 4;
 131→  TASK_STATUS_RUNNING           = 5;
 132→  TASK_STATUS_COMPLETED         = 6;
 133→  TASK_STATUS_FAILED            = 7;
 134→  TASK_STATUS_KILLED            = 8;
 135→}
 136→
 137→// Runtime backend used to isolate the agent process.
 138→enum RuntimeBackend {
 139→  RUNTIME_BACKEND_UNSPECIFIED = 0;
 140→  RUNTIME_BACKEND_BWRAP       = 1; // Linux bubblewrap namespaces
 141→  RUNTIME_BACKEND_DOCKER      = 2; // Docker container (macOS primary, Linux optional)
 142→  RUNTIME_BACKEND_HOST        = 3; // Explicit insecure host mode — no isolation
 143→}
 144→
 145→// Action taken on an approval request.
 146→enum ApprovalAction {
 147→  APPROVAL_ACTION_UNSPECIFIED = 0;
 148→  APPROVAL_ACTION_APPROVE     = 1;
 149→  APPROVAL_ACTION_DENY        = 2;
 150→}
 151→
 152→// Who is permitted to resolve an approval request.
 153→enum ApprovalActorKind {
 154→  APPROVAL_ACTOR_KIND_UNSPECIFIED = 0;
 155→  APPROVAL_ACTOR_KIND_PARENT_TASK = 1;
 156→  APPROVAL_ACTOR_KIND_OPERATOR    = 2;
 157→  APPROVAL_ACTOR_KIND_AUTO        = 3;
 158→}
 159→
 160→// Why an approval gate was triggered.
 161→enum ApprovalReasonKind {
 162→  APPROVAL_REASON_KIND_UNSPECIFIED            = 0;
 163→  APPROVAL_REASON_KIND_SOFT_CAP_EXCEEDED      = 1;
 164→  APPROVAL_REASON_KIND_CAPABILITY_ESCALATION  = 2;
 165→  APPROVAL_REASON_KIND_BUDGET_EXCEPTION       = 3;
 166→  APPROVAL_REASON_KIND_PROFILE_APPROVAL       = 4;
 167→  APPROVAL_REASON_KIND_MEMORY_PROMOTION       = 5;
 168→  APPROVAL_REASON_KIND_INSECURE_RUNTIME_RESTRICTION = 6;
 169→}
 170→
 171→// Current approval state of a task node.
 172→enum ApprovalState {
 173→  APPROVAL_STATE_UNSPECIFIED  = 0;
 174→  APPROVAL_STATE_NOT_REQUIRED = 1;
 175→  APPROVAL_STATE_PENDING      = 2;
 176→  APPROVAL_STATE_APPROVED     = 3;
 177→  APPROVAL_STATE_DENIED       = 4;
 178→}
 179→
 180→// Approval posture for child creation within a milestone or task envelope.
 181→enum ApprovalMode {
 182→  APPROVAL_MODE_UNSPECIFIED           = 0;
 183→  APPROVAL_MODE_AUTO_WITHIN_ENVELOPE  = 1;
 184→  APPROVAL_MODE_PARENT_WITHIN_ENVELOPE = 2;
 185→  APPROVAL_MODE_OPERATOR_REQUIRED     = 3;
 186→}
 187→
 188→// Memory scope for task data.
 189→enum MemoryScope {
 190→  MEMORY_SCOPE_UNSPECIFIED = 0;
 191→  MEMORY_SCOPE_SCRATCH     = 1; // Agent-local, lifetime = agent
 192→  MEMORY_SCOPE_RUN_SHARED  = 2; // Lane-scoped append-only by default, lifetime = run
 193→  MEMORY_SCOPE_PROJECT     = 3; // Cross-run durable, deny-by-default writes
 194→}
 195→
 196→// Default run-shared write model.
 197→enum RunSharedWriteMode {
 198→  RUN_SHARED_WRITE_MODE_UNSPECIFIED = 0;
 199→  RUN_SHARED_WRITE_MODE_APPEND_ONLY_LANE = 1;
 200→  RUN_SHARED_WRITE_MODE_COORDINATED_SHARED_WRITE = 2;
 201→}
 202→
 203→// Repository filesystem access level.
 204→enum RepoAccess {
 205→  REPO_ACCESS_UNSPECIFIED = 0;
 206→  REPO_ACCESS_NONE        = 1;
 207→  REPO_ACCESS_READ_ONLY   = 2;
 208→  REPO_ACCESS_READ_WRITE  = 3;
 209→}
 210→
 211→// Whether a credential is proxy-only or may be exported with explicit approval.
 212→enum CredentialAccessMode {
 213→  CREDENTIAL_ACCESS_MODE_UNSPECIFIED = 0;
 214→  CREDENTIAL_ACCESS_MODE_PROXY_ONLY  = 1;
 215→  CREDENTIAL_ACCESS_MODE_EXPORTABLE  = 2;
 216→}
 217→
 218→// Whether a parent waits for the child task to complete.
 219→enum TaskWaitMode {
 220→  TASK_WAIT_MODE_UNSPECIFIED         = 0;
 221→  TASK_WAIT_MODE_ASYNC               = 1;
 222→  TASK_WAIT_MODE_WAIT_FOR_COMPLETION = 2;
 223→}
 224→
 225→// Execution state of an operator-facing milestone.
 226→enum MilestoneStatus {
 227→  MILESTONE_STATUS_UNSPECIFIED = 0;
 228→  MILESTONE_STATUS_PENDING     = 1;
 229→  MILESTONE_STATUS_RUNNING     = 2;
 230→  MILESTONE_STATUS_BLOCKED     = 3;
 231→  MILESTONE_STATUS_COMPLETED   = 4;
 232→  MILESTONE_STATUS_FAILED      = 5;
 233→}
 234→
 235→// ---------------------------------------------------------------------------
 236→// Run lifecycle messages
 237→// ---------------------------------------------------------------------------
 238→
 239→message SubmitRunRequest {
 240→  // Project identifier (e.g. repository path or name).
 241→  string project = 1;
 242→
 243→  // Canonical run plan submitted by the client.
 244→  RunPlan plan = 2;
 245→
 246→  // Absolute path to the workspace root on the host.
 247→  string workspace = 3;
 248→
 249→  // Optional policy overrides supplied by the operator at submission time.
 250→  // These are merged on top of project and global policy and may only
 251→  // tighten constraints, never relax them beyond global policy.
 252→  PolicyOverrides policy_overrides = 4;
 253→
 254→  // Optional runtime backend preference. If unspecified the daemon
 255→  // auto-detects per Section 4.6.
 256→  RuntimeBackend runtime_backend = 5;
 257→
 258→  // Client-supplied idempotency key. If the daemon has already accepted a
 259→  // run with this key, it returns the existing RunInfo.
 260→  string idempotency_key = 6;
 261→
 262→  // Client authentication context — daemon may use this for audit and ACL.
 263→  ClientIdentity client_identity = 7;
 264→}
 265→
 266→// Policy overrides supplied at run submission time.
 267→message PolicyOverrides {
 268→  // Maximum total tasks across the entire run.
 269→  optional int32 max_tasks_total = 1;
 270→
 271→  // Maximum children any single task may spawn.
 272→  optional int32 max_children_per_task = 2;
 273→
 274→  // Maximum task tree depth.
 275→  optional int32 max_depth = 3;
 276→
 277→  // Maximum concurrently running agents.
 278→  optional int32 max_concurrent = 4;
 279→
 280→  // Hard cap on total tokens for the run.
 281→  optional int64 max_tokens_per_run = 5;
 282→
 283→  // Hard cap on tokens per individual task.
 284→  optional int64 max_tokens_per_task = 6;
 285→
 286→  // Percentage of budget at which to warn the parent.
 287→  optional int32 warn_at_percent = 7;
 288→
 289→  // Whether submission should require a secure runtime and refuse insecure host mode.
 290→  optional bool require_secure_runtime = 8;
 291→
 292→  // Additional network denials to tighten the effective policy.
 293→  repeated string network_denylist = 9;
 294→
 295→  // Additional credential denials to tighten the effective policy.
 296→  repeated string credential_denylist = 10;
 297→}
 298→
 299→// Snapshot of a run's current state.
 300→message RunInfo {
 301→  string id = 1;
 302→  string project = 2;
 303→  RunStatus status = 3;
 304→
 305→  // Top-level milestones (phases) in execution order.
 306→  repeated Milestone milestones = 4;
 307→
 308→  // Total number of task nodes (including children) in this run.
 309→  int32 task_count = 5;
 310→
 311→  // Cumulative token usage across all tasks in this run.
 312→  TokenUsage token_usage = 6;
 313→
 314→  // Estimated cost in USD.
 315→  double estimated_cost_usd = 7;
 316→
 317→  // Runtime backend in use for this run.
 318→  RuntimeBackend runtime_backend = 8;
 319→
 320→  // Whether the run is executing in insecure host mode.
 321→  bool insecure_host_runtime = 9;
 322→
 323→  google.protobuf.Timestamp submitted_at = 10;
 324→  google.protobuf.Timestamp started_at = 11;
 325→  google.protobuf.Timestamp finished_at = 12;
 326→
 327→  // Human-readable failure reason when status is FAILED or CANCELLED.
 328→  string failure_reason = 13;
 329→
 330→  // Canonical submitted plan persisted by the daemon.
 331→  RunPlan submitted_plan = 14;
 332→}
 333→
 334→// Canonical run plan owned by the daemon.
 335→message RunPlan {
 336→  uint32 version = 1;
 337→  repeated MilestonePlan milestones = 2;
 338→  repeated TaskTemplate initial_tasks = 3;
 339→  BudgetEnvelope global_budget = 4;
 340→}
 341→
 342→// A top-level phase / milestone in the submitted run plan.
 343→message MilestonePlan {
 344→  string id = 1;
 345→  string title = 2;
 346→  string objective = 3;
 347→  string expected_output = 4;
 348→  repeated string depends_on = 5;
 349→  repeated string success_criteria = 6;
 350→  string default_profile = 7;
 351→  BudgetEnvelope budget = 8;
 352→  ApprovalMode approval_mode = 9;
 353→}
 354→
 355→// Root task seeded when a run is first submitted.
 356→message TaskTemplate {
 357→  string milestone_id = 1;
 358→  string objective = 2;
 359→  string expected_output = 3;
 360→  string profile_hint = 4;
 361→  BudgetEnvelope budget = 5;
 362→  MemoryScope memory_scope = 6;
 363→  repeated string depends_on_task_ids = 7;
 364→}
 365→
 366→// A top-level phase / milestone snapshot within a running run.
 367→message Milestone {
 368→  string id = 1;
 369→  string title = 2;
 370→  int32 order = 3;
 371→  MilestoneStatus status = 4;
 372→  // Task nodes that belong to this milestone.
 373→  repeated string task_ids = 5;
 374→}
 375→
 376→// Cumulative token usage.
 377→message TokenUsage {
 378→  int64 input_tokens = 1;
 379→  int64 output_tokens = 2;
 380→  int64 cache_read_tokens = 3;
 381→  int64 cache_write_tokens = 4;
 382→  int64 total_tokens = 5;
 383→}
 384→
 385→message AttachRunRequest {
 386→  string run_id = 1;
 387→
 388→  // Replay events with cursor > after_cursor, then continue with a live tail.
 389→  int64 after_cursor = 2;
 390→
 391→  // Optional filter: only stream events for these task IDs.
 392→  repeated string task_id_filter = 3;
 393→
 394→  ClientIdentity client_identity = 4;
 395→}
 396→
 397→message StopRunRequest {
 398→  string run_id = 1;
 399→
 400→  // Grace period before force-killing agents. If unset, daemon uses its
 401→  // configured default (typically 30s).
 402→  google.protobuf.Duration grace_period = 2;
 403→
 404→  // Reason for stopping (recorded in audit trail).
 405→  string reason = 3;
 406→
 407→  ClientIdentity client_identity = 4;
 408→}
 409→
 410→message GetRunRequest {
 411→  string run_id = 1;
 412→}
 413→
 414→message ListRunsRequest {
 415→  // Filter by project. Empty means all projects.
 416→  string project = 1;
 417→
 418→  // Filter by status. Empty means all statuses.
 419→  repeated RunStatus status_filter = 2;
 420→
 421→  // Pagination.
 422→  int32 page_size = 3;
 423→  string page_token = 4;
 424→}
 425→
 426→message ListRunsResponse {
 427→  repeated RunInfo runs = 1;
 428→  string next_page_token = 2;
 429→}
 430→
 431→// ---------------------------------------------------------------------------
 432→// Task lifecycle messages
 433→// ---------------------------------------------------------------------------
 434→
 435→message GetTaskRequest {
 436→  string task_id = 1;
 437→}
 438→
 439→// Snapshot of a task node within the run graph.
 440→message TaskInfo {
 441→  string id = 1;
 442→  string run_id = 2;
 443→
 444→  // Parent task node ID. Empty for root / top-level tasks.
 445→  string parent_task_id = 3;
 446→
 447→  // Milestone this task belongs to (if any).
 448→  string milestone_id = 4;
 449→
 450→  // What the task should accomplish.
 451→  string objective = 5;
 452→
 453→  // What the task is expected to produce.
 454→  string expected_output = 6;
 455→
 456→  // Compiled profile name (e.g. "implementer", "security-reviewer").
 457→  string profile = 7;
 458→
 459→  // Token / resource budget for this task.
 460→  BudgetEnvelope budget = 8;
 461→
 462→  // Memory scope governing scratch, run-shared, or project access.
 463→  MemoryScope memory_scope = 9;
 464→
 465→  TaskStatus status = 10;
 466→
 467→  // Agent instance currently assigned to this task (if running).
 468→  string assigned_agent_id = 11;
 469→
 470→  // IDs of direct child task nodes.
 471→  repeated string children = 12;
 472→
 473→  // Resource snapshot of the assigned agent (if running).
 474→  ResourceSnapshot resource_snapshot = 13;
 475→
 476→  // Human-readable failure or kill reason.
 477→  string failure_reason = 14;
 478→
 479→  google.protobuf.Timestamp created_at = 15;
 480→  google.protobuf.Timestamp started_at = 16;
 481→  google.protobuf.Timestamp finished_at = 17;
 482→
 483→  // Token usage for this task (excluding children).
 484→  TokenUsage token_usage = 18;
 485→
 486→  // Cumulative token usage for this task's entire subtree.
 487→  TokenUsage subtree_token_usage = 19;
 488→
 489→  // Explicit dependency edges in the run graph.
 490→  repeated string depends_on_task_ids = 20;
 491→
 492→  // Current approval state for this task.
 493→  ApprovalState approval_state = 21;
 494→
 495→  // Approved capability envelope for this task subtree.
 496→  CapabilityEnvelope requested_capabilities = 22;
 497→
 498→  // Whether the parent waited for this task to complete.
 499→  TaskWaitMode wait_mode = 23;
 500→
 501→  // Persisted summary of the task result.
 502→  TaskResultSummary result_summary = 24;
 503→}
 504→
 505→// Budget envelope constraining a task's resource consumption.
 506→message BudgetEnvelope {
 507→  // Maximum tokens this task may consume.
 508→  int64 max_tokens = 1;
 509→
 510→  // Maximum wall-clock duration for this task.
 511→  google.protobuf.Duration max_duration = 2;
 512→
 513→  // Maximum number of child tasks this task may create.
 514→  int32 max_children = 3;
 515→
 516→  // Number of children after which approval is required.
 517→  int32 require_approval_after = 4;
 518→
 519→  // Maximum task tree depth below this node.
 520→  int32 max_depth = 5;
 521→}
 522→
 523→// Point-in-time resource consumption of an agent.
 524→message ResourceSnapshot {
 525→  string agent_id = 1;
 526→  string task_id = 2;
 527→
 528→  // CPU usage as a fraction (0.0 – N cores).
 529→  double cpu_usage = 3;
 530→
 531→  // Resident memory in bytes.
 532→  int64 memory_bytes = 4;
 533→
 534→  // Disk usage in bytes (task worktree).
 535→  int64 disk_bytes = 5;
 536→
 537→  // Network egress bytes since agent start.
 538→  int64 network_egress_bytes = 6;
 539→
 540→  // Network ingress bytes since agent start.
 541→  int64 network_ingress_bytes = 7;
 542→
 543→  google.protobuf.Timestamp sampled_at = 8;
 544→}
 545→
 546→message ListTasksRequest {
 547→  string run_id = 1;
 548→
 549→  // Optional: filter to tasks under this parent.
 550→  string parent_task_id = 2;
 551→
 552→  // Optional: filter by status.
 553→  repeated TaskStatus status_filter = 3;
 554→
 555→  // Optional: filter by milestone.
 556→  string milestone_id = 4;
 557→
 558→  int32 page_size = 5;
 559→  string page_token = 6;
 560→}
 561→
 562→message ListTasksResponse {
 563→  repeated TaskInfo tasks = 1;
 564→  string next_page_token = 2;
 565→}
 566→
 567→message StreamTaskOutputRequest {
 568→  string run_id = 1;
 569→  string task_id = 2;
 570→
 571→  // Replay output chunks with cursor > after_cursor.
 572→  int64 after_cursor = 3;
 573→
 574→  ClientIdentity client_identity = 4;
 575→}
 576→
 577→// A single output event projected from the authoritative runtime event log.
 578→message TaskOutputEvent {
 579→  string run_id = 1;
 580→  string task_id = 2;
 581→  string agent_id = 3;
 582→
 583→  // Authoritative runtime-event cursor for this output chunk.
 584→  int64 cursor = 4;
 585→
 586→  google.protobuf.Timestamp timestamp = 5;
 587→
 588→  oneof event {
 589→    // Raw stdout/stderr line from the agent process.
 590→    StdoutLine stdout_line = 6;
 591→
 592→    // Parsed signal tag (<progress>, <blocker>, <pivot>).
 593→    Signal signal = 7;
 594→
 595→    // Promise tag (<promise>DONE</promise>) indicating task completion.
 596→    Promise promise = 8;
 597→
 598→    // Token-usage delta parsed from structured agent output.
 599→    TokenUsageDelta token_usage = 9;
 600→  }
 601→}
 602→
 603→message StdoutLine {
 604→  string line = 1;
 605→  bool is_stderr = 2;
 606→}
 607→
 608→message Signal {
 609→  // Signal type: "progress", "blocker", "pivot".
 610→  string signal_type = 1;
 611→  string content = 2;
 612→}
 613→
 614→message Promise {
 615→  string value = 1;
 616→}
 617→
 618→message TokenUsageDelta {
 619→  int64 tokens = 1;
 620→  int64 cumulative = 2;
 621→}
 622→
 623→message CreateChildTaskRequest {
 624→  string run_id = 1;
 625→  string parent_task_id = 2;
 626→  string milestone_id = 3;
 627→
 628→  // Profile to use for the child agent (e.g. "implementer", "reviewer").
 629→  string profile = 4;
 630→
 631→  // What the child task should accomplish.
 632→  string objective = 5;
 633→
 634→  // What the child task is expected to produce.
 635→  string expected_output = 6;
 636→
 637→  // Budget overrides for the child. If unset, inherits from parent minus
 638→  // already consumed resources.
 639→  BudgetEnvelope budget = 7;
 640→
 641→  // Memory scope for the child. If unset, defaults to RUN_SHARED.
 642→  MemoryScope memory_scope = 8;
 643→
 644→  // Whether the parent should block until the child completes.
 645→  TaskWaitMode wait_mode = 9;
 646→
 647→  // Explicit dependency edges for the child task.
 648→  repeated string depends_on_task_ids = 10;
 649→
 650→  // Requested capability envelope for the child subtree.
 651→  CapabilityEnvelope requested_capabilities = 11;
 652→
 653→  // Client authentication context for audit.
 654→  ClientIdentity client_identity = 12;
 655→}
 656→
 657→message CreateChildTaskResponse {
