  1→//! Strongly-typed identifier newtypes for the Forge runtime domain.
  2→//!
  3→//! Each ID wraps a `String` and provides `Display`, `From<String>`, `AsRef<str>`,
  4→//! and serde support. Using newtype wrappers prevents accidental misuse of one
  5→//! identifier kind where another is expected (e.g., passing a `RunId` where an
  6→//! `AgentId` is required).
  7→
  8→use serde::{Deserialize, Serialize};
  9→use std::fmt;
 10→
 11→macro_rules! define_id {
 12→    ($(#[doc = $doc:expr])* $name:ident) => {
 13→        $(#[doc = $doc])*
 14→        #[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 15→        pub struct $name(String);
 16→
 17→        impl $name {
 18→            /// Create a new identifier from any string-like value.
 19→            pub fn new(id: impl Into<String>) -> Self {
 20→                Self(id.into())
 21→            }
 22→
 23→            /// Generate a new random identifier using a UUID v4.
 24→            pub fn generate() -> Self {
 25→                Self(uuid::Uuid::new_v4().to_string())
 26→            }
 27→
 28→            /// Return the inner string slice.
 29→            pub fn as_str(&self) -> &str {
 30→                &self.0
 31→            }
 32→
 33→            /// Consume the wrapper and return the inner `String`.
 34→            pub fn into_inner(self) -> String {
 35→                self.0
 36→            }
 37→        }
 38→
 39→        impl fmt::Display for $name {
 40→            fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 41→                write!(f, "{}", self.0)
 42→            }
 43→        }
 44→
 45→        impl From<String> for $name {
 46→            fn from(s: String) -> Self {
 47→                Self(s)
 48→            }
 49→        }
 50→
 51→        impl From<&str> for $name {
 52→            fn from(s: &str) -> Self {
 53→                Self(s.to_owned())
 54→            }
 55→        }
 56→
 57→        impl AsRef<str> for $name {
 58→            fn as_ref(&self) -> &str {
 59→                &self.0
 60→            }
 61→        }
 62→    };
 63→}
 64→
 65→define_id! {
 66→    /// Unique identifier for an entire run (a submitted plan execution).
 67→    RunId
 68→}
 69→
 70→define_id! {
 71→    /// Unique identifier for a task node within a run graph.
 72→    ///
 73→    /// Task nodes are the durable unit of work: they track dependencies, budget,
 74→    /// expected output, approvals, memory scope, and audit trail.
 75→    TaskNodeId
 76→}
 77→
 78→define_id! {
 79→    /// Unique identifier for an agent instance (the concrete worker process
 80→    /// executing a task node).
 81→    AgentId
 82→}
 83→
 84→define_id! {
 85→    /// Unique identifier for a milestone (operator-facing phase marker).
 86→    ///
 87→    /// Top-level phases remain user-visible milestones; runtime decomposition
 88→    /// produces child `TaskNode`s rather than sub-phases.
 89→    MilestoneId
 90→}
 91→
 92→define_id! {
 93→    /// Unique identifier for a pending approval request.
 94→    ///
 95→    /// Approval attaches to task-node creation — once approved, retries or
 96→    /// backend restarts do not re-prompt unless requested capabilities change.
 97→    ApprovalId
 98→}
 99→
100→define_id! {
101→    /// Unique identifier for a pending child-task spawn request that is
102→    /// awaiting approval.
103→    SpawnId
104→}
105→
106→define_id! {
107→    /// Unique identifier for a message bus channel (used for request/reply
108→    /// communication between task nodes).
109→    ChannelId
110→}
111→
112→#[cfg(test)]
113→mod tests {
114→    use super::*;
115→
116→    #[test]
117→    fn ids_are_distinct_types() {
118→        let run = RunId::new("r1");
119→        let task = TaskNodeId::new("r1");
120→        // Same inner value but different types — this is the point of newtypes.
121→        assert_eq!(run.as_str(), task.as_str());
122→        // Compile-time: you cannot pass a RunId where a TaskNodeId is expected.
123→    }
124→
125→    #[test]
126→    fn generate_produces_unique_ids() {
127→        let a = AgentId::generate();
128→        let b = AgentId::generate();
129→        assert_ne!(a, b);
130→    }
131→
132→    #[test]
133→    fn roundtrip_serde() {
134→        let id = RunId::new("test-run-123");
135→        let json = serde_json::to_string(&id).unwrap();
136→        let back: RunId = serde_json::from_str(&json).unwrap();
137→        assert_eq!(id, back);
138→    }
139→}
140→

