    let stale_runs = state_store.query_runs_by_status(&[
        "Submitted", "Running", "Paused",
    ])?;
    for run in &stale_runs {
        state_store.update_run_status(&run.id, RunStatus::Failed)?;
    }
    Ok(stale_runs.len())
}
