- [ ] **Step 1: Define ShutdownCoordinator**

```rust
pub struct ShutdownCoordinator {
    cancel_token: CancellationToken,
    orchestrator: Arc<Mutex<RunOrchestrator>>,
    state_store: Arc<StateStore>,
    event_bus: Arc<EventBus>,
    default_grace_period: Duration,
}
```

- [ ] **Step 2: Implement `initiate_shutdown`**

The shutdown sequence (per spec Section 6.7):
1. Cancel the `CancellationToken` to stop the scheduling loop
2. Emit `RuntimeEventKind::Shutdown` event with reason and grace period
3. Transition all `Running` and `Enqueued` tasks to `Killed { reason: "daemon_shutdown" }` -- actual agent killing is deferred to Plan 4 (runtime backends); for now, just update state
4. Transition all active runs to `RunStatus::Failed`
5. Flush all pending events to the event log
6. Close the state store connection

```rust
impl ShutdownCoordinator {
    pub async fn initiate_shutdown(
        &self,
        reason: String,
        grace_period: Option<Duration>,
    ) -> ShutdownResult {
        let grace = grace_period.unwrap_or(self.default_grace_period);
        self.cancel_token.cancel();

        let mut orch = self.orchestrator.lock().await;
        let mut agents_signaled = 0i32;

        // Mark all active tasks as killed
        for run in orch.run_graph.runs.values_mut() {
            if run.status == RunStatus::Running {
                for task in run.tasks.values_mut() {
                    if matches!(task.status, TaskStatus::Running { .. } | TaskStatus::Enqueued) {
                        agents_signaled += 1;
                        task.status = TaskStatus::Killed {
                            reason: "daemon_shutdown".into(),
                        };
                    }
                }
                run.status = RunStatus::Failed;
                run.finished_at = Some(Utc::now());
            }
        }

        // Flush event log and close DB
        drop(orch);
        self.state_store.flush();

        ShutdownResult { agents_signaled, grace_period: grace }
    }
}

pub struct ShutdownResult {
    pub agents_signaled: i32,
    pub grace_period: Duration,
}
```

