```rust
async fn attach_run(
    &self,
    request: Request<AttachRunRequest>,
) -> Result<Response<Self::AttachRunStream>, Status> {
    let req = request.into_inner();
    let run_id = RunId::new(&req.run_id);
    // Verify run exists
    let orch = self.orchestrator.lock().await;
    if orch.run_graph.get_run(&run_id).is_none() {
        return Err(Status::not_found("run not found"));
    }
    drop(orch);

    let task_filter: Vec<TaskNodeId> = req.task_id_filter.iter()
        .map(|s| TaskNodeId::new(s))
        .collect();
    let stream = self.event_bus.replay_and_stream(
        req.after_cursor as u64,
        Some(run_id),
        task_filter,
    ).await;
    Ok(Response::new(Box::pin(stream)))
}
```

